import { Link } from "react-router-dom";

export default function Logo({ className = "" }) {
    return (
        <Link 
            to="/" 
            className={`flex items-center gap-1 group transition-transform hover:scale-105 ${className}`}
        >
            {/* Logo - HTML/CSS based to avoid stretching */}
            <div className="flex items-center gap-0">
                {/* Shopping Bag Icon */}
                <div className="relative w-12 h-12 flex items-center justify-center">
                    <svg width="40" height="40" viewBox="0 0 40 40" fill="none" xmlns="http://www.w3.org/2000/svg">
                        {/* Bag handle */}
                        <path d="M 10 8 Q 10 2 20 2 Q 30 2 30 8" stroke="#0a0a0a" strokeWidth="2" fill="none" strokeLinecap="round"/>
                        {/* Bag body */}
                        <rect x="8" y="8" width="24" height="28" rx="2" stroke="#0a0a0a" strokeWidth="1.5" fill="none"/>
                        {/* Play button */}
                        <polygon points="20,16 20,26 28,21" fill="#FF9500"/>
                    </svg>
                </div>
                
                {/* Text Logo */}
                <div className="flex items-baseline gap-0.5">
                    <span className="font-serif text-lg font-normal text-espresso">Shop</span>
                    <span className="font-serif text-lg font-normal text-maroon">Live</span>
                    <span className="font-serif text-lg font-normal" style={{color: '#1B5E20'}}>Bharat</span>
                </div>
            </div>
        </Link>
    );
}
